package com.babidndn.order;
import com.babidndn.cart.*;import com.babidndn.common.NotFoundException;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.format.DateTimeFormatter;import java.util.*;
@Service public class OrderService { private final OrderRepository orders; private final CartService cartService; public OrderService(OrderRepository orders,CartService cartService){this.orders=orders;this.cartService=cartService;} public List<CustomerOrder> findAll(){return orders.findAllByOrderByCreatedAtDesc();} public CustomerOrder findById(Long id){return orders.findById(id).orElseThrow(()->new NotFoundException("order not found"));} @Transactional public CustomerOrder createFromCart(){List<CartItem> cart=cartService.findAll(); if(cart.isEmpty()) throw new IllegalArgumentException("cart is empty"); int total=cart.stream().mapToInt(CartItem::getLineTotal).sum(); CustomerOrder order=new CustomerOrder("BBD-"+DateTimeFormatter.ofPattern("MMddHHmmss").format(java.time.LocalDateTime.now()),total); for(CartItem c:cart){order.addItem(new OrderItem(c.getMenu().getId(),c.getMenu().getName(),c.getMenu().getPrice(),c.getQuantity(),c.getOptionSummary(),c.getOptionPrice()));} CustomerOrder saved=orders.save(order); cartService.clear(); return saved;} public CustomerOrder changeStatus(Long id,OrderStatus status){CustomerOrder order=findById(id); order.changeStatus(status); return orders.save(order);} }
